insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('spanish:6-1-celebrities-influencers-and-fame:mcq:9fda324f', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'mcq', 'mcq', 1, '{"question": "What does ‘la letra de la canción’ mean?", "options": ["the lyrics of the song", "the melody and rhythm of a song", "the price of a single song download", "the length of the song in minutes"]}'::jsonb, '{"answer": 0, "explain": "la letra = the lyrics (of a song) — also means ‘letter’ of the alphabet in other contexts."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:mcq:e8a70673', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'mcq', 'mcq', 1, '{"question": "What does ‘un buen comportamiento’ mean?", "options": ["good behaviour", "a good haircut", "a good salary", "a good relationship with fans"]}'::jsonb, '{"answer": 0, "explain": "el comportamiento = behaviour. The press often comments on a celebrity''s comportamiento."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:mcq:06cb6763', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'mcq', 'mcq', 1, '{"question": "What does ‘relacionarse con los fans’ mean?", "options": ["to interact with the fans", "to ignore the fans completely", "to avoid meeting the fans", "to sell tickets to the fans"]}'::jsonb, '{"answer": 0, "explain": "relacionarse con = to interact / relate to. Many celebrities relacionarse con (interact with) fans on social media."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:mcq:a6bc403e', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'mcq', 'mcq', 1, '{"question": "Which phrase correctly means ‘the best actor’?", "options": ["el mejor actor", "el más actor", "el actor mejor que", "un actor más bueno"]}'::jsonb, '{"answer": 0, "explain": "‘el mejor’ is the irregular superlative of bueno and already means ‘the best’ — Spanish never adds ‘más’ in front of it."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:mcq:6d60c470', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'mcq', 'mcq', 1, '{"question": "What does ‘Estoy seguro de que va a ganar el premio’ mean?", "options": ["I am sure that she is going to win the prize", "I am afraid that she is going to lose the prize", "I hope that she is going to win the prize eventually", "I doubt that she is ever going to win the prize"]}'::jsonb, '{"answer": 0, "explain": "estar seguro de que = to be sure that. The other options change the meaning to fear, hope or doubt."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:4550d6ee', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "‘la fama’ means ‘the family’."}'::jsonb, '{"answer": false, "explain": "la fama = fame; la familia = family — similar spelling, different meaning."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:b20d4b3d', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "‘seguir a’ + a person needs the personal ‘a’."}'::jsonb, '{"answer": true, "explain": "Sigo A mi cantante favorita — the personal ‘a’ is required before a person."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:64034a34', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "After ‘creo que’ (a positive opinion), Spanish uses the ordinary indicative: creo que es…"}'::jsonb, '{"answer": true, "explain": "Positive opinions keep the indicative; only a NEGATIVE opinion triggers the subjunctive."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:cca034d9', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "After ‘no creo que’ (a negative opinion), Spanish uses the subjunctive: no creo que sea…"}'::jsonb, '{"answer": true, "explain": "H: no creo que + subjunctive (sea), not the indicative (es)."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:a2f54f84', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "‘tener éxito’ means ‘to have an exit’."}'::jsonb, '{"answer": false, "explain": "False friend! tener éxito means to be successful."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:8e3dbd0d', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "‘más famoso que’ means ‘as famous as’."}'::jsonb, '{"answer": false, "explain": "más…que = more…than. ‘As…as’ would be tan…como."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:45c2173d', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "Giving money to charity is an example of using fame in a positive way."}'::jsonb, '{"answer": true, "explain": "dar dinero a organizaciones benéficas is a classic advantage of fame."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:4bdc7d20', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "Losing your privacy is listed as an ADVANTAGE of being famous."}'::jsonb, '{"answer": false, "explain": "Losing your privacy (perder la privacidad) is a DISADVANTAGE, not an advantage."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:5b42cbea', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "‘Estoy seguro de que…’ means ‘I doubt that…’."}'::jsonb, '{"answer": false, "explain": "estar seguro de que = to be sure that — the opposite of doubting (dudar que)."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:903eb1b8', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "‘el mejor actor’ means ‘the best actor’."}'::jsonb, '{"answer": true, "explain": "el mejor is the irregular superlative of bueno, meaning ‘the best’."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:3e73d192', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "‘Se separaron el año pasado’ means they got married last year."}'::jsonb, '{"answer": false, "explain": "separarse = to split up, the opposite of casarse (to get married)."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:c5c45e65', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "‘la telerrealidad’ refers to reality TV shows."}'::jsonb, '{"answer": true, "explain": "la telerrealidad = reality TV, a genre closely linked to celebrity culture."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tf:8f459c01', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tf', 'tf', 1, '{"question": "‘Tiene mucho talento’ means ‘she has a lot of luck’."}'::jsonb, '{"answer": false, "explain": "el talento = talent; luck is la suerte — a common mix-up."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:af1c8352', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "Who and what is famous? (fame vocabulary)", "reading": "<p>The key noun is <span data-say=\"la fama\">la fama</span> (fame). Someone who has it is <span data-say=\"famoso\">famoso</span> / <span data-say=\"famosa\">famosa</span> (famous). Tap 🔊 to hear the core vocabulary.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la estrella\">la estrella</span></td><td>the star (celebrity)</td><td><span data-say=\"el cantante\">el cantante / la cantante</span></td><td>singer</td></tr>\n              <tr><td><span data-say=\"el actor\">el actor</span></td><td>actor</td><td><span data-say=\"la actriz\">la actriz</span></td><td>actress</td></tr>\n              <tr><td><span data-say=\"el futbolista\">el futbolista / la futbolista</span></td><td>footballer</td><td><span data-say=\"el influencer\">el influencer / la influencer</span></td><td>influencer</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Mi ídolo es una cantante muy famosa.\">Mi ídolo es una cantante muy famosa.</span> — <em>My idol is a very famous singer.</em></p>", "question": "What does ‘la estrella’ mean in this context?", "options": ["the (celebrity) star", "the actual night sky", "a type of award ceremony", "a person who dislikes fame"]}'::jsonb, '{"answer": 0, "explain": "la estrella = the star, meaning a famous celebrity — not a star in the sky."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:acc9136a', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "Social media and success", "reading": "<p>Fame today is closely linked to <span data-say=\"las redes sociales\">las redes sociales</span> (social media). To follow someone, use <strong>seguir a</strong> — always with the personal <strong>a</strong> before a person.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"seguir a\">seguir a (alguien)</span></td><td>to follow (someone)</td><td><span data-say=\"el seguidor\">el seguidor / la seguidora</span></td><td>follower</td></tr>\n              <tr><td><span data-say=\"tener éxito\">tener éxito</span></td><td>to be successful</td><td><span data-say=\"el éxito\">el éxito</span></td><td>success</td></tr>\n              <tr><td><span data-say=\"ser rico\">ser rico / rica</span></td><td>to be rich</td><td><span data-say=\"ganar mucho dinero\">ganar mucho dinero</span></td><td>to earn a lot of money</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Sigo a mi cantante favorita porque tiene mucho éxito.\">Sigo a mi cantante favorita porque tiene mucho éxito.</span> — <em>I follow my favourite singer because she is very successful.</em></p>", "question": "‘tener éxito’ is a false friend. What does it actually mean?", "options": ["to be successful", "to have an exit", "to lose all your money", "to feel very tired"]}'::jsonb, '{"answer": 0, "explain": "tener éxito = to be successful. It looks like the English word ‘exit’ but does not mean that at all."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:65fbed73', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "How do I give an opinion about a celebrity?", "reading": "<p>Start an opinion with a set phrase, then give a <strong>reason</strong> with <span data-say=\"porque\">porque</span>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"creo que\">creo que…</span></td><td>I think that…</td><td><span data-say=\"pienso que\">pienso que…</span></td><td>I think that…</td></tr>\n              <tr><td><span data-say=\"en mi opinión\">en mi opinión…</span></td><td>in my opinion…</td><td><span data-say=\"me parece que\">me parece que…</span></td><td>it seems to me that…</td></tr>\n            </table>\n            <p>Role-model vocabulary: <span data-say=\"mi ídolo\">mi ídolo</span> (my idol), <span data-say=\"admirar\">admirar</span> (to admire), <span data-say=\"respetar\">respetar</span> (to respect), and <span data-say=\"un buen modelo a seguir\">un buen modelo a seguir</span> / <span data-say=\"un mal modelo a seguir\">un mal modelo a seguir</span> (a good / bad role model).</p>\n            <p>Example: <span data-say=\"Creo que es un buen modelo a seguir porque ayuda a mucha gente.\">Creo que es un buen modelo a seguir porque ayuda a mucha gente.</span></p>", "question": "Which word introduces the REASON in an opinion sentence?", "options": ["porque (because)", "sin embargo (however)", "cuando (when)", "donde (where)"]}'::jsonb, '{"answer": 0, "explain": "porque = because, introducing the reason after an opinion phrase like ‘creo que’. ‘sin embargo’ is a genuine trap — it also links ideas, but it means ‘however’, not ‘because’."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:bc6b6229', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "The advantages of fame", "reading": "<p>Famous people can use their platform positively:</p>\n            <ul>\n              <li><span data-say=\"la ventaja\">la ventaja</span> — the advantage</li>\n              <li><span data-say=\"ayudar a la gente\">ayudar a la gente</span> — to help people</li>\n              <li><span data-say=\"dar dinero a organizaciones benéficas\">dar dinero a organizaciones benéficas</span> — to give money to charities</li>\n              <li><span data-say=\"ser una buena influencia\">ser una buena influencia</span> — to be a good influence</li>\n            </ul>\n            <p>Example: <span data-say=\"Una ventaja de la fama es que puedes ayudar a la gente y dar dinero a organizaciones benéficas.\">Una ventaja de la fama es que puedes ayudar a la gente y dar dinero a organizaciones benéficas.</span></p>", "question": "‘dar dinero a organizaciones benéficas’ means…", "options": ["to give money to charities", "to borrow money from a bank", "to earn money from adverts", "to spend money on clothes"]}'::jsonb, '{"answer": 0, "explain": "dar dinero a organizaciones benéficas = to give money to charities — a common advantage of fame in exam answers."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:251b8286', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "The disadvantages of fame", "reading": "<p>Exam answers should also weigh up the negatives — <span data-say=\"la desventaja\">la desventaja</span> (the disadvantage):</p>\n            <ul>\n              <li><span data-say=\"perder la privacidad\">perder la privacidad</span> — to lose your privacy</li>\n              <li><span data-say=\"sentir mucha presión\">sentir mucha presión</span> — to feel a lot of pressure</li>\n              <li><span data-say=\"ser una mala influencia\">ser una mala influencia</span> — to be a bad influence</li>\n            </ul>\n            <p>Example: <span data-say=\"Sin embargo, los famosos pierden la privacidad y sienten mucha presión.\">Sin embargo, los famosos pierden la privacidad y sienten mucha presión.</span> — <em>However, celebrities lose their privacy and feel a lot of pressure.</em></p>", "question": "What is ‘sentir mucha presión’ describing?", "options": ["feeling a lot of pressure", "feeling completely relaxed", "earning a lot of money", "losing a lot of followers"]}'::jsonb, '{"answer": 0, "explain": "sentir mucha presión = to feel a lot of pressure, a key disadvantage of fame."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:279709f8', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "Higher: the subjunctive and comparatives", "reading": "<p><span class=\"tier-h\">H</span> After a <strong>POSITIVE</strong> opinion, Spanish uses the normal indicative: <span data-say=\"Creo que es un buen modelo a seguir.\">Creo que es un buen modelo a seguir.</span></p>\n            <p><span class=\"tier-h\">H</span> But after a <strong>NEGATIVE</strong> opinion (<em>no creo que…</em>), Spanish switches to the <strong>subjunctive</strong>:</p>\n            <ul>\n              <li><span data-say=\"No creo que sea un buen modelo a seguir.\">No creo que sea un buen modelo a seguir.</span> <span class=\"tier-h\">H</span> — I don’t think he/she is a good role model.</li>\n              <li><span data-say=\"No creo que la fama sea fácil.\">No creo que la fama sea fácil.</span> <span class=\"tier-h\">H</span> — I don’t think fame is easy.</li>\n            </ul>\n            <p>Comparatives use <strong>más… que</strong> (more… than):</p>\n            <p><span data-say=\"Es más famoso que su hermano.\">Es más famoso que su hermano.</span> — <em>He is more famous than his brother.</em></p>", "question": "Which sentence correctly uses the subjunctive after a NEGATIVE opinion?", "options": ["No creo que sea un buen modelo a seguir.", "No creo que es un buen modelo a seguir de verdad.", "Creo que sea un buen modelo a seguir.", "No creo un buen modelo a seguir."]}'::jsonb, '{"answer": 0, "explain": "no creo que + subjunctive → sea. Option B wrongly uses the indicative ‘es’ (plus ‘de verdad’, really); C uses the subjunctive after a POSITIVE opinion by mistake."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:0c551198', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "Love, marriage and family status", "reading": "<p>Celebrity gossip often centres on <span data-say=\"el amor\">el amor</span> (love) and <span data-say=\"la relación\">la relación</span> (relationship). Two people who are together are <span data-say=\"la pareja\">la pareja</span> (a couple/partner).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"casarse con\">casarse (con)</span></td><td>to get married (to)</td><td><span data-say=\"casado\">casado / casada</span></td><td>married</td></tr>\n              <tr><td><span data-say=\"el matrimonio\">el matrimonio</span></td><td>marriage</td><td><span data-say=\"el marido\">el marido</span></td><td>husband</td></tr>\n              <tr><td><span data-say=\"separarse\">separarse</span></td><td>to split up</td><td><span data-say=\"divorciarse\">divorciarse</span></td><td>to get divorced</td></tr>\n              <tr><td><span data-say=\"soltero\">soltero / soltera</span></td><td>single</td><td><span data-say=\"nacer\">nacer</span></td><td>to be born</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"La actriz se casó con el cantante en 2019, pero se separaron el año pasado y ahora está soltera otra vez.\">La actriz se casó con el cantante en 2019, pero se separaron el año pasado y ahora está soltera otra vez.</span> — <em>The actress married the singer in 2019, but they split up last year and now she is single again.</em></p>\n            <p>Sadly, some stars have <span data-say=\"muerto\">muerto</span> (died) young — the press calls this a tragedy.</p>", "question": "What does ‘se separaron’ mean?", "options": ["they split up", "they got married", "they were born", "they became famous overnight"]}'::jsonb, '{"answer": 0, "explain": "separarse = to split up / separate. It is the opposite of casarse (to get married)."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:d7c7f5e4', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "Media: press, TV, radio and interviews", "reading": "<p>Fame is created and spread by <span data-say=\"los medios de comunicación\">los medios de comunicación</span> (the media): <span data-say=\"la prensa\">la prensa</span> (the press), <span data-say=\"la radio\">la radio</span> (radio) and <span data-say=\"la tele\">la tele</span> / <span data-say=\"la televisión\">la televisión</span> (TV).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la entrevista\">la entrevista</span></td><td>the interview</td><td><span data-say=\"el comentario\">el comentario</span></td><td>comment</td></tr>\n              <tr><td><span data-say=\"el anuncio\">el anuncio</span></td><td>advert / announcement</td><td><span data-say=\"el espectáculo\">el espectáculo</span></td><td>the show</td></tr>\n              <tr><td><span data-say=\"grabar\">grabar</span></td><td>to record</td><td><span data-say=\"el sonido\">el sonido</span></td><td>sound</td></tr>\n              <tr><td><span data-say=\"digital\">digital</span> <span class=\"tier-h\">H</span></td><td>digital</td><td><span data-say=\"la telerrealidad\">la telerrealidad</span></td><td>reality TV</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En la entrevista, la estrella hizo un comentario sobre la telerrealidad y luego grabó un anuncio para la tele.\">En la entrevista, la estrella hizo un comentario sobre la telerrealidad y luego grabó un anuncio para la tele.</span> — <em>In the interview, the star made a comment about reality TV and then recorded an advert for TV.</em></p>", "question": "What is ‘la telerrealidad’?", "options": ["reality TV", "a local radio station", "a newspaper article", "a live outdoor concert"]}'::jsonb, '{"answer": 0, "explain": "la telerrealidad = reality TV, a TV genre often linked to celebrity culture."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:bc349a52', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "Fame, society, nation and politics", "reading": "<p>Some celebrities use their fame to talk about <span data-say=\"la sociedad\">la sociedad</span> (society) and <span data-say=\"la política\">la política</span> <span class=\"tier-h\">H</span> (politics) — for example, encouraging fans to <span data-say=\"votar\">votar</span> (to vote).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"nacional\">nacional</span> <span class=\"tier-h\">H</span></td><td>national</td><td><span data-say=\"internacional\">internacional</span> <span class=\"tier-h\">H</span></td><td>international</td></tr>\n              <tr><td><span data-say=\"mundial\">mundial</span> <span class=\"tier-h\">H</span></td><td>world(wide)</td><td><span data-say=\"la cultura\">la cultura</span></td><td>culture</td></tr>\n              <tr><td><span data-say=\"cultural\">cultural</span></td><td>cultural</td><td><span data-say=\"la identidad\">la identidad</span></td><td>identity</td></tr>\n              <tr><td><span data-say=\"la nacionalidad\">la nacionalidad</span> <span class=\"tier-h\">H</span></td><td>nationality</td><td><span data-say=\"la discriminación\">la discriminación</span> <span class=\"tier-h\">H</span></td><td>discrimination</td></tr>\n              <tr><td><span data-say=\"el conflicto\">el conflicto</span> <span class=\"tier-h\">H</span></td><td>conflict</td><td><span data-say=\"la víctima\">la víctima</span> <span class=\"tier-h\">H</span></td><td>victim</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Es una cantante de fama mundial que habla sobre la discriminación en la sociedad y anima a sus fans a votar.\">Es una cantante de fama mundial que habla sobre la discriminación en la sociedad y anima a sus fans a votar.</span> — <em>She is a singer of worldwide fame who talks about discrimination in society and encourages her fans to vote.</em></p>\n            <p>Some celebrities campaign for the <span data-say=\"la realidad\">la realidad</span> (reality) of the <span data-say=\"víctimas\">víctimas</span> of conflict to be taken seriously.</p>", "question": "What does ‘la discriminación’ mean?", "options": ["discrimination", "a discount on a concert ticket", "a type of TV discussion show", "a national election result"]}'::jsonb, '{"answer": 0, "explain": "la discriminación = discrimination — many celebrities campaign against it in society."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:633f8c13', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "Careers in the arts and sport", "reading": "<p>Fame comes from many different careers — <span data-say=\"la carrera\">la carrera</span> (career). Someone creative is <span data-say=\"el artista\">el artista / la artista</span> (artist).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el escritor\">el escritor / la escritora</span></td><td>writer</td><td><span data-say=\"el autor\">el autor / la autora</span></td><td>author</td></tr>\n              <tr><td><span data-say=\"el músico\">el músico / la música</span></td><td>musician</td><td><span data-say=\"la banda\">la banda</span></td><td>band</td></tr>\n              <tr><td><span data-say=\"el pintor\">el pintor / la pintora</span></td><td>painter</td><td><span data-say=\"el protagonista\">el/la protagonista</span> <span class=\"tier-h\">H</span></td><td>main character</td></tr>\n              <tr><td><span data-say=\"el deportista\">el/la deportista</span></td><td>sportsperson</td><td><span data-say=\"el jugador\">el jugador / la jugadora</span></td><td>player</td></tr>\n              <tr><td><span data-say=\"el personaje\">el personaje</span></td><td>the character</td><td><span data-say=\"la obra\">la obra</span> <span class=\"tier-h\">H</span></td><td>the (creative) work</td></tr>\n            </table>\n            <p>To start something new, use <span data-say=\"fundar\">fundar</span> <span class=\"tier-h\">H</span> (to found) and <span data-say=\"dirigir\">dirigir</span> <span class=\"tier-h\">H</span> (to direct/manage). Example: <span data-say=\"El escritor fundó su propia editorial y ahora dirige un nuevo proyecto en la industria musical.\">El escritor fundó su propia editorial y ahora dirige un nuevo proyecto en la industria musical.</span> — <em>The writer founded his own publishing house and now directs a new project in the music industry.</em></p>", "question": "What does ‘dirigir’ mean in this context?", "options": ["to direct or manage", "to write a whole song''s lyrics", "to sell tickets for a concert", "to give a short television interview"]}'::jsonb, '{"answer": 0, "explain": "dirigir = to direct or manage (a project, a company, a film)."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:learn:f1749651', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'learn', 'mcq', 1, '{"readingTitle": "Personality, talent, image and trends", "reading": "<p>Fans often discuss a celebrity''s <span data-say=\"la personalidad\">la personalidad</span> (personality) and <span data-say=\"el carácter\">el carácter</span> (character) — plus their <span data-say=\"la imagen\">la imagen</span> (image) and <span data-say=\"el estilo\">el estilo</span> (style).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el talento\">el talento</span> <span class=\"tier-h\">H</span></td><td>talent</td><td><span data-say=\"la generación\">la generación</span> <span class=\"tier-h\">H</span></td><td>generation</td></tr>\n              <tr><td><span data-say=\"artístico\">artístico / artística</span></td><td>artistic</td><td><span data-say=\"musical\">musical</span></td><td>musical</td></tr>\n              <tr><td><span data-say=\"la moda\">la moda</span></td><td>fashion</td><td><span data-say=\"de moda\">de moda</span></td><td>fashionable / trendy</td></tr>\n              <tr><td><span data-say=\"la tendencia\">la tendencia</span> <span class=\"tier-h\">H</span></td><td>trend</td><td><span data-say=\"el lujo\">el lujo</span> <span class=\"tier-h\">H</span></td><td>luxury</td></tr>\n              <tr><td><span data-say=\"el sueño\">el sueño</span></td><td>dream</td><td><span data-say=\"la imaginación\">la imaginación</span> <span class=\"tier-h\">H</span></td><td>imagination</td></tr>\n              <tr><td><span data-say=\"orgulloso\">orgulloso / orgullosa</span> <span class=\"tier-h\">H</span></td><td>proud</td><td><span data-say=\"apropiado\">apropiado / apropiada</span> <span class=\"tier-h\">H</span></td><td>appropriate</td></tr>\n              <tr><td><span data-say=\"guapo\">guapo / guapa</span></td><td>good-looking</td><td colspan=\"2\"></td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Tiene mucho talento e imaginación, siempre lleva ropa de moda y está muy orgullosa de su estilo artístico.\">Tiene mucho talento e imaginación, siempre lleva ropa de moda y está muy orgullosa de su estilo artístico.</span> — <em>She has a lot of talent and imagination, she always wears fashionable clothes and is very proud of her artistic style.</em></p>", "question": "What does ‘orgullosa’ describe in this sentence?", "options": ["feeling proud", "feeling embarrassed", "feeling completely exhausted", "feeling nervous about an interview"]}'::jsonb, '{"answer": 0, "explain": "orgulloso/orgullosa = proud. It agrees in gender with the person it describes."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:misc:139c3465', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Sigo mi cantante favorita.</p><p><strong>✅ The correct idea:</strong> Sigo a mi cantante favorita.</p>", "question": "What is missing from ‘Sigo mi cantante favorita’?", "options": ["the personal ‘a’ before a person", "an accent on the word ‘cantante’", "the article ‘la’ before ‘cantante’", "the reflexive pronoun ‘me’"]}'::jsonb, '{"answer": 0, "explain": "seguir a + a person always needs the personal ‘a’: sigo A mi cantante favorita."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:misc:fae57f79', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Creo que es un modelo a seguir bueno.</p><p><strong>✅ The correct idea:</strong> Creo que es un buen modelo a seguir.</p>", "question": "Why does ‘bueno’ change to ‘buen’ here?", "options": ["‘bueno’ shortens to ‘buen’ before a masculine singular noun", "‘bueno’ is always spelt ‘buen’ in Spanish", "‘modelo’ is actually a feminine noun, so the adjective form has to change here", "adjectives always go after the noun in Spanish"]}'::jsonb, '{"answer": 0, "explain": "bueno shortens to buen directly before a masculine singular noun (un buen modelo), unlike most adjectives which follow the noun. ‘modelo’ is in fact masculine, which is what makes option C a real trap."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:misc:e49ff8e5', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> No creo que es un buen modelo a seguir.</p><p><strong>✅ The correct idea:</strong> No creo que sea un buen modelo a seguir.</p>", "question": "Why is ‘No creo que es…’ wrong at Higher tier?", "options": ["a negative opinion (no creo que) always needs the verb in the subjunctive, here ‘sea’", "‘es’ should always become ‘está’ after the word ‘que’, whatever the opinion happens to be", "the sentence needs the word ‘porque’ added", "‘creo’ should be ‘creí’ (past tense)"]}'::jsonb, '{"answer": 0, "explain": "H: no creo que + SUBJUNCTIVE (sea). Using the indicative ‘es’ after a negative opinion is the classic Higher-tier error."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:misc:c367fbef', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Tiene mucho éxito. (I understand this as ‘has many exits’)</p><p><strong>✅ The correct idea:</strong> Tiene mucho éxito. (= is very successful)</p>", "question": "What does ‘éxito’ really mean here?", "options": ["success", "an exit from a building", "money or riches", "fame on social media only"]}'::jsonb, '{"answer": 0, "explain": "éxito = success (false friend with English ‘exit’, which in Spanish is ‘la salida’)."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:misc:fa3b994d', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Es más famoso como su hermano.</p><p><strong>✅ The correct idea:</strong> Es más famoso que su hermano.</p>", "question": "Which linking word completes a comparative (‘more…than’)?", "options": ["que", "como", "cuando", "donde"]}'::jsonb, '{"answer": 0, "explain": "más + adjective + QUE = more…than. ‘como’ (as) is used in a different structure (tan…como)."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tips:24e9d884', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Dictation (listening)", "reading": "Celebrity-culture sentences reuse chunks you know: ‘creo que…’, ‘sigo a…’, ‘tiene éxito’. Listen for whether an opinion is positive (creo que + indicative) or negative (no creo que + subjunctive) — the verb ending changes.", "question": "You hear ‘…no creo que sea…’. What form is ‘sea’?", "options": ["the subjunctive, after a negative opinion", "just the ordinary present tense, nothing special", "a completed past-tense action", "a direct command"]}'::jsonb, '{"answer": 0, "explain": "‘sea’ is the subjunctive form of ser, triggered by the negative opinion ‘no creo que’."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tips:b1143425', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 3 — Reading &amp; translation into English", "reading": "Watch the false friends: ‘éxito’ = success, not exit; ‘privacidad’ = privacy. Keep translations natural: ‘she loses her privacy’, not a word-for-word rendering.", "question": "‘Los famosos pierden la privacidad y sienten mucha presión’ =", "options": ["Celebrities lose their privacy and feel a lot of pressure", "Celebrities carefully protect their privacy and feel very relaxed", "Celebrities earn a lot of money and gain many followers", "Celebrities admire their idols and respect their fans"]}'::jsonb, '{"answer": 0, "explain": "pierden la privacidad = lose their privacy; sienten mucha presión = feel a lot of pressure."}'::jsonb),
('spanish:6-1-celebrities-influencers-and-fame:tips:2f1a4fab', 'spanish', 'spanish:6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Paper 4 — Writing &amp; translation into Spanish", "reading": "Combine an opinion, a reason and a weighed-up view: ‘Creo que es un buen modelo a seguir porque ayuda a la gente, pero no creo que la fama sea fácil.’ At Higher, the subjunctive after a negative opinion is a strong feature to include.", "question": "Which answer reaches the top band?", "options": ["Creo que es un buen modelo a seguir porque ayuda a la gente, pero no creo que la fama sea fácil", "Es famosa y muy famosa y increíblemente famosa y tiene mucho dinero y mucho éxito todo el tiempo sin parar nunca", "Es famosa", "Tiene éxito"]}'::jsonb, '{"answer": 0, "explain": "It links a positive opinion with a reason AND a Higher-tier subjunctive clause — range and accuracy beats a rambling, repetitive list of adjectives."}'::jsonb),
